import java.io.IOException;
import java.io.PrintWriter;

import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly encoding user input before including it in the HTML response
        String safeUserInput = Encode.forHtml(userInput);
        String htmlResponse = "<html><body>" + safeUserInput + "</body></html>";

        try {
            PrintWriter out = new PrintWriter("index.html");
            out.println(htmlResponse);
            out.close();
            System.out.println("HTML file generated successfully.");
        } catch (IOException e) {
            System.out.println("Error generating HTML file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
